const pueData = $('Get Current PUE').first().json;
const sensorData = $('Get Environmental Sensors').first().json;

// Extract sensor readings
const sensors = sensorData.data || sensorData.sensors || [];

// ASHRAE Guidelines
const ASHRAE_RECOMMENDED_MAX = 27;
const ASHRAE_ALLOWABLE_MAX = 32;
const CRITICAL_TEMP = 35;
const HUMIDITY_MIN = 20;
const HUMIDITY_MAX = 80;

// Temperature Analysis
const tempSensors = sensors.filter(s => s.type === 'temperature' || s.sensorType === 'temperature');
const humiditySensors = sensors.filter(s => s.type === 'humidity' || s.sensorType === 'humidity');

// Identify hotspots
const hotspots = tempSensors
  .filter(s => (s.value || s.reading) > ASHRAE_RECOMMENDED_MAX)
  .map(s => ({
    sensorId: s.id,
    location: s.location || s.cabinet || 'Unknown',
    temperature: s.value || s.reading,
    severity: (s.value || s.reading) > CRITICAL_TEMP ? 'critical' : 
              (s.value || s.reading) > ASHRAE_ALLOWABLE_MAX ? 'high' : 'warning'
  }))
  .sort((a, b) => b.temperature - a.temperature);

// Calculate averages
const avgTemp = tempSensors.length > 0 
  ? tempSensors.reduce((sum, s) => sum + (s.value || s.reading || 0), 0) / tempSensors.length 
  : 0;

const avgHumidity = humiditySensors.length > 0
  ? humiditySensors.reduce((sum, s) => sum + (s.value || s.reading || 0), 0) / humiditySensors.length
  : 0;

// Humidity issues
const humidityIssues = humiditySensors
  .filter(s => (s.value || s.reading) < HUMIDITY_MIN || (s.value || s.reading) > HUMIDITY_MAX)
  .map(s => ({
    sensorId: s.id,
    location: s.location || s.cabinet || 'Unknown',
    humidity: s.value || s.reading,
    issue: (s.value || s.reading) < HUMIDITY_MIN ? 'too_low' : 'too_high'
  }));

// PUE Analysis
const currentPue = pueData.pue || pueData.currentPue || pueData.data?.pue || 0;
const itPower = pueData.itPowerKw || pueData.it_power_kw || pueData.data?.it_power_kw || 0;
const facilityPower = pueData.facilityPowerKw || pueData.facility_power_kw || pueData.data?.facility_power_kw || 0;

const pueStatus = currentPue > 2.0 ? 'critical' :
                 currentPue > 1.8 ? 'poor' :
                 currentPue > 1.5 ? 'average' :
                 currentPue > 1.3 ? 'good' : 'excellent';

const hasCriticalIssues = hotspots.some(h => h.severity === 'critical') || currentPue > 2.0;
const hasWarnings = hotspots.length > 0 || currentPue > 1.6 || humidityIssues.length > 0;

return {
  json: {
    timestamp: new Date().toISOString(),
    pue: {
      current: parseFloat(currentPue.toFixed(3)),
      status: pueStatus,
      itPowerKw: parseFloat(itPower.toFixed(2)),
      facilityPowerKw: parseFloat(facilityPower.toFixed(2)),
      coolingOverhead: parseFloat((facilityPower - itPower).toFixed(2))
    },
    thermal: {
      avgTemperature: parseFloat(avgTemp.toFixed(1)),
      avgHumidity: parseFloat(avgHumidity.toFixed(1)),
      sensorCount: tempSensors.length,
      hotspotCount: hotspots.length,
      criticalHotspots: hotspots.filter(h => h.severity === 'critical'),
      allHotspots: hotspots.slice(0, 10) // Top 10
    },
    humidity: {
      issueCount: humidityIssues.length,
      issues: humidityIssues.slice(0, 5)
    },
    alerts: {
      hasCriticalIssues,
      hasWarnings,
      summary: hasCriticalIssues ? 'CRITICAL: Immediate attention required' :
               hasWarnings ? 'WARNING: Issues detected' : 'OK: All metrics within normal range'
    }
  }
};

